    while(!q.empty()){
        ll u=q.front();
        q.pop();

        for(ll v: adj[u]){
            if(vis[v])continue;
            vis[v] = 1;
            dis[v] = dis[u] + 1;
            q.push(v);
        }
    }
}

void BFS(int startx, int starty, ll N, ll M, vector<vb> &vis, vvll &dis){
    queue<pll> q;
    vis[startx][starty] = 1;
    dis[startx][starty] = 0;
    q.push({startx, starty});

    while(!q.empty()){
        pll u=q.front();
        ll ux=u.first, uy = u.second;
        q.pop();

        for(auto [vx, vy]: get_moves(ux, uy, N, M)){
            if(vis[vx][vy])continue;
            vis[vx][vy] = 1;
            dis[vx][vy] = dis[ux][uy] + 1;
            q.push({vx, vy});
        }
    }
