    ll ans = 0;

    cin>>N>>M>>L;
    vll a(N);
    Nfor0(i, N) cin>>a[i];

    multiset<ll> animatronics;
    Nfor0(i, M) animatronics.insert(0);
    Nfor0(i, N){
        timepass(a[i] - ((i > 0) ? a[i-1] : 0), N-i+1, animatronics);
        debug(animatronics);
    }
    ans = -*animatronics.begin() + L - a[N-1];

    println(ans);
}

